sso.get_credentials:

CACHE_FILE=$(ls -t ~/.aws/sso/cache/*.json | xargs grep -l '"startUrl"' | head -1)
TOKEN=$(python3 -c "import json; print(json.load(open('$CACHE_FILE'))['accessToken'])")
eval $(aws sso get-role-credentials --access-token "$TOKEN" \
  --account-id 277802554323 --role-name AWSAdministratorAccess --region us-east-1 \
  | python3 -c "import json,sys; c=json.load(sys.stdin)['roleCredentials'];
    print(f'export AWS_ACCESS_KEY_ID={c[\"accessKeyId\"]}');
    print(f'export AWS_SECRET_ACCESS_KEY={c[\"secretAccessKey\"]}');
    print(f'export AWS_SESSION_TOKEN={c[\"sessionToken\"]}')")
export AWS_REGION=us-east-1

workflows.aws_credentials_step:

- name: Configure AWS credentials
  uses: aws-actions/configure-aws-credentials@v6.0.0
  with:
    role-to-assume: ${{ secrets.AWS_ROLE_ARN }}
    aws-region: us-east-1
    role-session-name: GitHubActions-{Deploy|Init|Destroy}

workflows.image_versioning:
- If HEAD has a git tag (e.g. v1.0.0) use the tag as the image version
- Otherwise use short SHA: sha-${GITHUB_SHA::7}
- Always also tag as "latest"
